fn task_definition_cached<'b>(
    &self,
    turbo_json_loader: &'b L,
    task_id: &Spanned<TaskId>,
    task_name: &TaskName,
    chain_cache: &mut HashMap<PackageName, Vec<&'b TurboJson>>,
) -> Result<TaskDefinition, BuilderError> {
    let processed_task_definition = ProcessedTaskDefinition::from_iter(
        self.task_definition_chain_cached(turbo_json_loader, task_id, task_name, chain_cache)?,
    );
    let path_to_root = self.path_to_root(task_id.as_inner())?;
    TaskDefinition::from_processed(processed_task_definition, &path_to_root)
}

fn from_raw(
    raw_task: turborepo_turbo_json::RawTaskDefinition,
    path_to_repo_root: &RelativeUnixPath,
) -> Result<TaskDefinition, BuilderError> {
    use turborepo_turbo_json::FutureFlags;
    // Use default FutureFlags for backward compatibility
    let processed = ProcessedTaskDefinition::from_raw(raw_task, &FutureFlags::default())?;
    <TaskDefinition as TaskDefinitionFromProcessed>::from_processed(
        processed,
        path_to_repo_root,
    )
}

impl Default for TaskDefinition {
    fn default() -> Self {
        Self {
            cache: true,
            outputs: Default::default(),
            env: Default::default(),
            pass_through_env: Default::default(),
            topological_dependencies: Default::default(),
            task_dependencies: Default::default(),
            inputs: Default::default(),
            output_logs: Default::default(),
            persistent: Default::default(),
            interruptible: Default::default(),
            interactive: Default::default(),
            env_mode: Default::default(),
            with: Default::default(),
        }
    }
}

/// Trait for types that provide task definition information needed for hashing.
///
/// This allows task_hash to be decoupled from the full TaskDefinition type
/// while still having access to the fields it needs for hash computation.
///
/// # Implementors
/// - `TaskDefinition` (implemented below)

fn hashable_outputs(&self, task_id: &TaskId) -> TaskOutputs {
    // Delegate to the canonical implementation in TaskDefinition
    TaskDefinition::hashable_outputs(self, task_id.task())
}

