/// Checks if there's a task definition in the current run
pub fn has_task_definition_in_run(
    loader: &L,
    workspace: &PackageName,
    task_name: &TaskName<'static>,
    task_id: &TaskId,
) -> Result<bool, BuilderError> {
    let result = Self::has_task_definition_in_run_inner(
        loader,
        workspace,
        task_name,
        task_id,
        &mut HashSet::new(),
    )?;
    Ok(result.has_definition())
}

fn has_task_definition_in_run_inner(
    loader: &L,
    workspace: &PackageName,
    task_name: &TaskName<'static>,
    task_id: &TaskId,
    visited: &mut HashSet<PackageName>,
) -> Result<TaskDefinitionResult, BuilderError> {
    // Avoid infinite loops from cyclic extends
    if visited.contains(workspace) {
        return Ok(TaskDefinitionResult::not_found());
    }
    visited.insert(workspace.clone());

    let turbo_json = loader.load(workspace).map_or_else(
        |err| {
            if err.is_no_turbo_json() && !matches!(workspace, PackageName::Root) {
                Ok(None)
            } else {
                Err(err)
            }
        },
        |turbo_json| Ok(Some(turbo_json)),
    )?;

    let Some(turbo_json) = turbo_json else {
        // If there was no turbo.json in the workspace, fallback to the root turbo.json
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    };

    let task_id_as_name = task_id.as_task_name();

    // Helper to check task definition status based on extends configuration
    let check_task_def = |task_def: &RawTaskDefinition| -> TaskDefinitionResult {
        let has_extends_false = task_def
            .extends
            .as_ref()
            .map(|e| !*e.as_inner())
            .unwrap_or(false);

        if has_extends_false && !task_def.has_config_beyond_extends() {
            // Task is explicitly excluded via `extends: false` with no config
            TaskDefinitionResult::excluded()
        } else {
            // Task exists (either with `extends: false` + config, or normal definition)
            TaskDefinitionResult::found()
        }
    };

    // Check if this package's turbo.json has the task defined under various key
    // formats
    let base_task_name = TaskName::from(task_name.task());
    let check_base_task = matches!(workspace, PackageName::Root)
        || workspace == &PackageName::from(task_id.package());

    // Try task keys in order of specificity: task_id, task_name, base_task_name
    let task_def = turbo_json
        .tasks
        .get(&task_id_as_name)
        .or_else(|| turbo_json.tasks.get(task_name))
        .or_else(|| {
            if check_base_task {
                turbo_json.tasks.get(&base_task_name)
            } else {
                None
            }
        });

    if let Some(task_def) = task_def {
        return Ok(check_task_def(task_def));
    }

    // Check the extends chain for the task definition
    // Track if any package in the chain excluded this task
    for extend in turbo_json.extends.as_inner().iter() {
        let extend_package = PackageName::from(extend.as_str());
        let result = Self::has_task_definition_in_run_inner(
            loader,
            &extend_package,
            task_name,
            task_id,
            visited,
        )?;
        // If any package in the chain excluded this task, propagate that exclusion
        if result.is_excluded() {
            return Ok(TaskDefinitionResult::excluded());
        }
        if result.has_definition() {
            return Ok(TaskDefinitionResult::found());
        }
    }

    // This fallback only applies when there's no explicit `extends` field.
    // If `extends` is present (even if it only contains non-root packages),
    // we don't implicitly fall back to root since the validator ensures
    // the extends chain will eventually reach root.
    if turbo_json.extends.is_empty() && !matches!(workspace, PackageName::Root) {
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    }

    Ok(TaskDefinitionResult::not_found())
}

/// Resolves the merged `TaskDefinition` for a task, caching the turbo.json
/// chain per package. The chain only depends on the package name (not the
/// task), so multiple tasks in the same package share the cached chain.
fn task_definition_cached<'b>(
    &self,
    turbo_json_loader: &'b L,
    task_id: &Spanned<TaskId>,
    task_name: &TaskName,
    chain_cache: &mut HashMap<PackageName, Vec<&'b TurboJson>>,
) -> Result<TaskDefinition, BuilderError> {
    let processed_task_definition = ProcessedTaskDefinition::from_iter(
        self.task_definition_chain_cached(turbo_json_loader, task_id, task_name, chain_cache)?,
    );
    let path_to_root = self.path_to_root(task_id.as_inner())?;
    TaskDefinition::from_processed(processed_task_definition, &path_to_root)
}

/// Like `task_definition_chain` but caches the turbo.json chain per
/// package.
fn task_definition_chain_cached<'b>(
    &self,
    turbo_json_loader: &'b L,
    task_id: &Spanned<TaskId>,
    task_name: &TaskName,
    chain_cache: &mut HashMap<PackageName, Vec<&'b TurboJson>>,
) -> Result<Vec<ProcessedTaskDefinition>, BuilderError> {
    let package_name = PackageName::from(task_id.package());
    let turbo_json_chain = match chain_cache.get(&package_name) {
        Some(cached) => cached.clone(),
        None => {
            let chain = self.turbo_json_chain(turbo_json_loader, &package_name)?;
            chain_cache.insert(package_name, chain.clone());
            chain
        }
    };

    Self::resolve_task_definitions_from_chain(
        turbo_json_chain,
        task_id,
        task_name,
        self.is_single,
        self.should_validate_engine,
    )
}

pub fn task_definition_chain(
    &self,
    turbo_json_loader: &L,
    task_id: &Spanned<TaskId>,
    task_name: &TaskName,
) -> Result<Vec<ProcessedTaskDefinition>, BuilderError> {
    let package_name = PackageName::from(task_id.package());
    let turbo_json_chain = self.turbo_json_chain(turbo_json_loader, &package_name)?;
    Self::resolve_task_definitions_from_chain(
        turbo_json_chain,
        task_id,
        task_name,
        self.is_single,
        self.should_validate_engine,
    )

fn has_task_definition_in_run_inner(
    loader: &L,
    workspace: &PackageName,
    task_name: &TaskName<'static>,
    task_id: &TaskId,
    visited: &mut HashSet<PackageName>,
) -> Result<TaskDefinitionResult, BuilderError> {
    // Avoid infinite loops from cyclic extends
    if visited.contains(workspace) {
        return Ok(TaskDefinitionResult::not_found());
    }
    visited.insert(workspace.clone());

    let turbo_json = loader.load(workspace).map_or_else(
        |err| {
            if err.is_no_turbo_json() && !matches!(workspace, PackageName::Root) {
                Ok(None)
            } else {
                Err(err)
            }
        },
        |turbo_json| Ok(Some(turbo_json)),
    )?;

    let Some(turbo_json) = turbo_json else {
        // If there was no turbo.json in the workspace, fallback to the root turbo.json
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    };

    let task_id_as_name = task_id.as_task_name();

    // Helper to check task definition status based on extends configuration
    let check_task_def = |task_def: &RawTaskDefinition| -> TaskDefinitionResult {
        let has_extends_false = task_def
            .extends
            .as_ref()
            .map(|e| !*e.as_inner())
            .unwrap_or(false);

        if has_extends_false && !task_def.has_config_beyond_extends() {
            // Task is explicitly excluded via `extends: false` with no config
            TaskDefinitionResult::excluded()
        } else {
            // Task exists (either with `extends: false` + config, or normal definition)
            TaskDefinitionResult::found()
        }
    };

    // Check if this package's turbo.json has the task defined under various key
    // formats
    let base_task_name = TaskName::from(task_name.task());
    let check_base_task = matches!(workspace, PackageName::Root)
        || workspace == &PackageName::from(task_id.package());

    // Try task keys in order of specificity: task_id, task_name, base_task_name
    let task_def = turbo_json
        .tasks
        .get(&task_id_as_name)
        .or_else(|| turbo_json.tasks.get(task_name))
        .or_else(|| {
            if check_base_task {
                turbo_json.tasks.get(&base_task_name)
            } else {
                None
            }
        });

    if let Some(task_def) = task_def {
        return Ok(check_task_def(task_def));
    }

    // Check the extends chain for the task definition
    // Track if any package in the chain excluded this task
    for extend in turbo_json.extends.as_inner().iter() {
        let extend_package = PackageName::from(extend.as_str());
        let result = Self::has_task_definition_in_run_inner(
            loader,
            &extend_package,
            task_name,
            task_id,
            visited,
        )?;
        // If any package in the chain excluded this task, propagate that exclusion
        if result.is_excluded() {
            return Ok(TaskDefinitionResult::excluded());
        }
        if result.has_definition() {
            return Ok(TaskDefinitionResult::found());
        }
    }

    // This fallback only applies when there's no explicit `extends` field.
    // If `extends` is present (even if it only contains non-root packages),
    // we don't implicitly fall back to root since the validator ensures
    // the extends chain will eventually reach root.
    if turbo_json.extends.is_empty() && !matches!(workspace, PackageName::Root) {
        return Self::has_task_definition_in_run_inner(
            loader,
            &PackageName::Root,
            task_name,
            task_id,
            visited,
        );
    }

    Ok(TaskDefinitionResult::not_found())
}

/// Simple struct containing just the task definition fields needed by the
/// engine. This is the default task definition info type used when no custom
/// type is provided.
#[derive(Debug, Clone, Default)]

pub fn has_task_definition_in_run(
    loader: &L,
    workspace: &PackageName,
    task_name: &TaskName<'static>,
    task_id: &TaskId,
) -> Result<bool, BuilderError> {
    let result = Self::has_task_definition_in_run_inner(
        loader,
        workspace,
        task_name,
        task_id,
        &mut HashSet::new(),
    )?;
    Ok(result.has_definition())
}

pub struct TaskDefinitionResult {
    /// True if the task has a valid definition.
    has_definition: bool,
    /// True if the task was excluded via `extends: false` somewhere in the
    /// chain.
    is_excluded: bool,
}

pub fn new(
    task_definition: &TaskDefinition,
    env_vars: DetailedMap,
    env_at_execution_start: &EnvironmentVariableMap,
) -> Result<Self, turborepo_env::Error> {
    // TODO: this operation differs from the actual env that gets passed in during
    // task execution it should be unified, but first we should copy Go's
    // behavior as we try to match the implementations
    let pass_through = task_definition
        .pass_through_env
        .as_deref()
        .map(|pass_through_env| -> Result<_, turborepo_env::Error> {
            Ok(env_at_execution_start
                .from_wildcards(pass_through_env)?
                .to_secret_hashable())
        })
        .transpose()?;

    Ok(Self {
        specified: TaskEnvConfiguration {
            env: task_definition.env.clone(),
            pass_through_env: task_definition.pass_through_env.clone(),
        },
        configured: env_vars.by_source.explicit.to_secret_hashable(),
        inferred: env_vars.by_source.matching.to_secret_hashable(),
        pass_through,
    })
}

fn shared<T>(
    &self,
    task_id: &TaskId<'static>,
    execution: Option<TaskExecutionSummary>,
    workspace_info: &PackageInfo,
    display_task: impl Fn(&TaskId<'static>) -> Option<T> + Copy,
) -> Result<SharedTaskSummary<T>, Error> {
    // TODO: command should be optional
    let command = workspace_info
        .package_json
        .scripts
        .get(task_id.task())
        .map(|script| script.as_inner())
        .cloned()
        .unwrap_or_else(|| "<NONEXISTENT>".to_string());

    let task_definition = self.task_definition(task_id)?;

    let expanded_outputs = self
        .hash_tracker
        .expanded_outputs(task_id)
        .unwrap_or_default();

    let framework = self.hash_tracker.framework(task_id).unwrap_or_default();

    let hash = self
        .hash_tracker
        .hash(task_id)
        .unwrap_or_else(|| panic!("hash not found for {task_id}"));

    let expanded_inputs: std::collections::BTreeMap<_, _> = self
        .hash_tracker
        .expanded_inputs(task_id)
        .expect("inputs not found")
        .into_iter()
        .collect();

    let env_vars = self
        .hash_tracker
        .env_vars(task_id)
        .expect("env var map is inserted at the same time as hash");

    let cache_summary = TaskCacheSummary::from(self.hash_tracker.cache_status(task_id));

    let (dependencies, dependents) = self.dependencies_and_dependents(task_id, display_task);

    let log_file = task_definition.cache.then(|| {
        let path = workspace_info.package_path().to_owned();
        let relative_log_file = workspace_relative_log_file(task_id.task());
        path.join(&relative_log_file).to_string()
    });

    let with = task_definition
        .with
        .as_ref()
        .map(|with| {
            with.iter()
                .map(|task| task.as_inner().to_string())
                .collect()
        })
        .unwrap_or_default();

    // Compute external deps hash from workspace info
    let hash_of_external_dependencies =
        get_external_deps_hash(&workspace_info.transitive_dependencies);

    Ok(SharedTaskSummary {
        hash,
        inputs: expanded_inputs,
        hash_of_external_dependencies,
        cache: cache_summary,
        command,
        cli_arguments: self.run_opts.pass_through_args().to_vec(),
        outputs: match task_definition.outputs.inclusions.is_empty() {
            false => Some(task_definition.outputs.inclusions.clone()),
            true => None,
        },
        excluded_outputs: match task_definition.outputs.exclusions.is_empty() {
            true => None,
            false => Some(task_definition.outputs.exclusions.clone()),
        },
        log_file,
        directory: Some(workspace_info.package_path().to_string()),
        resolved_task_definition: task_definition.clone().into(),
        expanded_outputs,
        framework,
        dependencies,
        dependents,
        with,
        env_mode: self.global_env_mode,
        environment_variables: TaskEnvVarSummary::from_hash_tracker(
            task_definition,
            env_vars,
            self.env_at_start,
        )
        .expect("invalid glob in task definition should have been caught earlier"),
        execution,
    })
}

pub fn from_hash_tracker(
    task_definition: &TaskDefinition,
    env_vars: HashTrackerDetailedMap,
    env_at_execution_start: &EnvironmentVariableMap,
) -> Result<Self, turborepo_env::Error> {
    let pass_through = task_definition
        .pass_through_env
        .as_deref()
        .map(|pass_through_env| -> Result<_, turborepo_env::Error> {
            Ok(env_at_execution_start
                .from_wildcards(pass_through_env)?
                .to_secret_hashable())
        })
        .transpose()?;

    Ok(Self {
        specified: TaskEnvConfiguration {
            env: task_definition.env.clone(),
            pass_through_env: task_definition.pass_through_env.clone(),
        },
        configured: env_vars.explicit,
        inferred: env_vars.matching,
        pass_through,
    })
}

fn task_definition(&self, task_id: &TaskId<'static>) -> Result<&TaskDefinition, Error> {
    self.engine
        .task_definition(task_id)
        .ok_or_else(|| Error::MissingTask(task_id.clone().into_owned()))
}

pub fn has_task_definition_in_repo(
    loader: &L,
    package_graph: &PackageGraph,
    task_name: &TaskName<'static>,
) -> Result<bool, BuilderError> {
    for (package, _) in package_graph.packages() {
        let task_id = task_name
            .task_id()
            .unwrap_or_else(|| TaskId::new(package.as_str(), task_name.task()));
        if Self::has_task_definition_in_run(loader, package, task_name, &task_id)? {
            return Ok(true);
        }
    }
    Ok(false)
}
